const cfg = $('Set Config').first().json;
let products = $('Get Products').all().map(i => i.json);
const keyCol = cfg.keyColumn || 'Product No.';
const catCol = cfg.categoryColumn || 'Category_Name';

// ── Auto-fix col_N naming (fallback if header row not detected by n8n) ────
let headerMap = null;
if (products.length > 0) {
  const usesColN = Object.keys(products[0]).some(k => /^col_\d+$/.test(k));
  if (usesColN) {
    const hIdx = products.findIndex(p =>
      Object.values(p).some(v => String(v || '').trim() === keyCol)
    );
    if (hIdx >= 0) {
      const hRow = products[hIdx];
      headerMap = {};
      for (const [k, v] of Object.entries(hRow)) {
        const name = String(v || '').trim();
        if (name) headerMap[k] = name;
      }
      products = products.slice(hIdx + 1);
    }
  }
}
function getVal(p, colName) {
  if (!headerMap) return String(p[colName] || '');
  const entry = Object.entries(headerMap).find(([, v]) => v === colName);
  return entry ? String(p[entry[0]] || '') : '';
}
// ─────────────────────────────────────────────────────────────────────────

const IMAGE_COLS = [
  'IMAGE URL1','IMAGE URL2','IMAGE URL3','IMAGE URL4','IMAGE URL5',
  'IMAGE URL6','IMAGE URL7','IMAGE URL8','IMAGE URL9','IMAGE URL10'
];

function getFirstImage(p) {
  for (const col of IMAGE_COLS) {
    const v = getVal(p, col).trim();
    if (v && (v.startsWith('http://') || v.startsWith('https://'))) return v;
  }
  return '';
}

const PROMPT = `You are a specialist in stone wall panel products.
Analyze the product image and do TWO things:

━━━ STEP 1: CLASSIFY ━━━
Assign the product to ONE code from this list:

A  — Marble decorative breeze blocks
     Perforated / carved / breathable stone screens; stone lattice / jali / screen panels;
     decorative perforated walls; ventilation + light-filtering stone facades;
     carved geometric screen walls.

B1 — Architectural Surface Systems › Linear & Fluted Collections
     Vertical grooves, ribbed / fluted stone panels, rhythmic extrusion surfaces.

B2 — Architectural Surface Systems › Geometric & Faceted Collections
     Diamond cuts, angled planes, 3D geometric stone reliefs.

B3 — Architectural Surface Systems › Sculptural & Parametric Panels
     Organic shapes, algorithmic / flowing forms, custom CNC sculpted stone walls.



━━━ STEP 2: NAME ━━━
Generate a short, descriptive product name (3-6 words) that clearly describes
the surface. Focus on the material and the finish/shape feature.
Examples: "Fluted Marble Wall Panel", "Split Face Travertine Panel",
"Carved Marble Breeze Block Screen", "Diamond Cut Limestone Wall Panel",
"Brushed Basalt Stone Panel", "Herringbone Stone Mosaic Panel".

━━━ OUTPUT ━━━
Return ONLY a single valid JSON object - no markdown, no extra text:
{
  "category_code": "A|B1|B2|B3",
  "category_name": "exact parent category name from above",
  "subcategory_name": "subcategory name, or empty string if none",
  "wall_panel_name": "your generated descriptive product name"
}`;

const out = [];
for (const p of products) {
  const key = getVal(p, keyCol).trim();
  if (!key) continue;

  // Skip if already classified (either field filled = already processed)
  const cat = getVal(p, catCol).trim();
  const col1 = getVal(p, 'Collection_ID1').trim();
  if (cat || col1) continue;

  // Must have an image URL
  const img = getFirstImage(p);
  if (!img) continue;

  out.push({ json: { key, imageUrl: img, prompt: PROMPT } });
}

return out;

const aiItems = $input.all();
const src = $('Filter & Build Prompts').all();
const cfg = $('Set Config').first().json;

const collectionMap = {
  'A':  { id1: cfg.collectionId_A,  id2: '' },
  'B1': { id1: cfg.collectionId_B,  id2: cfg.collectionId_B1 },
  'B2': { id1: cfg.collectionId_B,  id2: cfg.collectionId_B2 },
  'B3': { id1: cfg.collectionId_B,  id2: cfg.collectionId_B3 },
};

const CATEGORY_NAMES = {
  'A':  { cat: 'Marble decorative breeze blocks',     sub: '' },
  'B1': { cat: 'Architectural Surface Systems',       sub: 'Linear & Fluted Collections' },
  'B2': { cat: 'Architectural Surface Systems',       sub: 'Geometric & Faceted Collections' },
  'B3': { cat: 'Architectural Surface Systems',       sub: 'Sculptural & Parametric Panels' },
};

const out = [];
for (let i = 0; i < aiItems.length; i++) {
  const r = aiItems[i].json || {};

  // Resolve the product key: Gemini node passes through the input json,
  // so r.key is the fastest path; fall back to the paired src item.
  const productKey = (typeof r.key === 'string' && r.key)
    ? r.key
    : (src[i] ? String(src[i].json.key || '') : '');

  // Gemini dedicated node returns { content: { parts: [{ text: "..." }], role: "model" } }
  let content = '';
  if (r.content && r.content.parts && r.content.parts[0]) {
    content = r.content.parts[0].text || '';
  }
  // Fallbacks for other response shapes
  if (!content && r.candidates && r.candidates[0]) {
    const parts = r.candidates[0].content?.parts;
    content = (parts && parts[0]?.text) || '';
  }
  if (!content) content = r.text || '';
  content = String(content).replace(/```json/gi, '').replace(/```/g, '').trim();

  let ai = {};
  try { ai = JSON.parse(content); } catch (e) { ai = {}; }

  const code  = (ai.category_code || '').trim().toUpperCase();
  if (!collectionMap[code]) continue;  // skip C/D or unknown codes
  const ids   = collectionMap[code];
  const names = CATEGORY_NAMES[code];

  out.push({
    json: {
      'Product No.':      productKey,
      'Category_Name':    names.cat,
      'Subcategory_Name': names.sub,
      'Wall_Panel_Name':  ai.wall_panel_name || '',
      'Collection_ID1':   String(ids.id1 || ''),
      'Collection_ID2':   String(ids.id2 || '')
    }
  });
}

return out;
